from abc import ABC, abstractmethod

class BaseTestEnvironment(ABC):
    @abstractmethod
    def setup(self) -> None: ...

    @abstractmethod
    def teardown(self) -> None: ...

    @abstractmethod
    def get_base_url(self) -> str: ...

class DockerEnvironment(BaseTestEnvironment):
    def setup(self): self._container = start_docker()
    def teardown(self): self._container.stop()
    def get_base_url(self): return 'http://localhost:8080'
